package com.enterprise.saml.service;

import com.enterprise.saml.model.SamlAssertion;
import com.enterprise.saml.model.SamlAssertion.SamlAttribute;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.*;
import org.xml.sax.InputSource;

import javax.xml.XMLConstants;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.StringReader;
import java.time.Instant;
import java.util.Base64;

@Service
public class SamlXmlParserService {

    private static final Logger logger = LoggerFactory.getLogger(SamlXmlParserService.class);

    private static final String SAML2_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";
    private static final String SAML2_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";

    public String decodeBase64SamlResponse(String encodedResponse) {
        byte[] decodedBytes = Base64.getDecoder().decode(encodedResponse);
        return new String(decodedBytes);
    }

    public Document parseXml(String xml) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);

        // Security: prevent XXE attacks
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        InputSource inputSource = new InputSource(new StringReader(xml));
        return builder.parse(inputSource);
    }

    public SamlAssertion extractAssertion(Document document) throws Exception {
        SamlAssertion assertion = new SamlAssertion();

        // Extract Status Code
        NodeList statusCodeNodes = document.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");
        if (statusCodeNodes.getLength() > 0) {
            Element statusCodeElement = (Element) statusCodeNodes.item(0);
            assertion.setStatusCode(statusCodeElement.getAttribute("Value"));
        }

        // Extract Response attributes
        NodeList responseNodes = document.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "Response");
        if (responseNodes.getLength() > 0) {
            Element responseElement = (Element) responseNodes.item(0);
            assertion.setInResponseTo(responseElement.getAttribute("InResponseTo"));
        }

        // Extract Assertion
        NodeList assertionNodes = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
        if (assertionNodes.getLength() == 0) {
            throw new SamlProcessingException("No SAML Assertion found in the response");
        }

        Element assertionElement = (Element) assertionNodes.item(0);
        assertion.setId(assertionElement.getAttribute("ID"));

        String issueInstantStr = assertionElement.getAttribute("IssueInstant");
        if (issueInstantStr != null && !issueInstantStr.isEmpty()) {
            assertion.setIssueInstant(Instant.parse(issueInstantStr));
        }

        // Extract Issuer
        NodeList issuerNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            assertion.setIssuer(issuerNodes.item(0).getTextContent().trim());
        }

        // Extract Subject / NameID
        NodeList nameIdNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
        if (nameIdNodes.getLength() > 0) {
            Element nameIdElement = (Element) nameIdNodes.item(0);
            assertion.setNameId(nameIdElement.getTextContent().trim());
            assertion.setNameIdFormat(nameIdElement.getAttribute("Format"));
        }

        // Extract SubjectConfirmationData
        NodeList subjectConfirmationDataNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "SubjectConfirmationData");
        if (subjectConfirmationDataNodes.getLength() > 0) {
            Element scd = (Element) subjectConfirmationDataNodes.item(0);
            assertion.setRecipient(scd.getAttribute("Recipient"));
            String notOnOrAfterStr = scd.getAttribute("NotOnOrAfter");
            if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
                assertion.setNotOnOrAfter(Instant.parse(notOnOrAfterStr));
            }
        }

        // Extract Conditions
        NodeList conditionsNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");
        if (conditionsNodes.getLength() > 0) {
            Element conditionsElement = (Element) conditionsNodes.item(0);
            String notBeforeStr = conditionsElement.getAttribute("NotBefore");
            String notOnOrAfterStr = conditionsElement.getAttribute("NotOnOrAfter");

            if (notBeforeStr != null && !notBeforeStr.isEmpty()) {
                assertion.setNotBefore(Instant.parse(notBeforeStr));
            }
            if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
                assertion.setNotOnOrAfter(Instant.parse(notOnOrAfterStr));
            }

            // Extract AudienceRestriction
            NodeList audienceNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Audience");
            if (audienceNodes.getLength() > 0) {
                assertion.setAudience(audienceNodes.item(0).getTextContent().trim());
            }
        }

        // Extract AuthnStatement
        NodeList authnStatementNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnStatement");
        if (authnStatementNodes.getLength() > 0) {
            Element authnStatement = (Element) authnStatementNodes.item(0);
            assertion.setSessionIndex(authnStatement.getAttribute("SessionIndex"));

            String authnInstantStr = authnStatement.getAttribute("AuthnInstant");
            if (authnInstantStr != null && !authnInstantStr.isEmpty()) {
                assertion.setAuthnInstant(Instant.parse(authnInstantStr));
            }

            String sessionNotOnOrAfterStr = authnStatement.getAttribute("SessionNotOnOrAfter");
            if (sessionNotOnOrAfterStr != null && !sessionNotOnOrAfterStr.isEmpty()) {
                // Store in assertion for session timeout
            }

            // Extract AuthnContextClassRef
            NodeList authnContextClassRefNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnContextClassRef");
            if (authnContextClassRefNodes.getLength() > 0) {
                assertion.setAuthnContextClassRef(authnContextClassRefNodes.item(0).getTextContent().trim());
            }
        }

        // Extract AttributeStatement
        NodeList attributeStatementNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeStatement");
        if (attributeStatementNodes.getLength() > 0) {
            Element attributeStatement = (Element) attributeStatementNodes.item(0);
            NodeList attributeNodes = attributeStatement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Attribute");

            for (int i = 0; i < attributeNodes.getLength(); i++) {
                Element attributeElement = (Element) attributeNodes.item(i);
                SamlAttribute samlAttribute = new SamlAttribute();
                samlAttribute.setName(attributeElement.getAttribute("Name"));
                samlAttribute.setNameFormat(attributeElement.getAttribute("NameFormat"));

                NodeList valueNodes = attributeElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeValue");
                for (int j = 0; j < valueNodes.getLength(); j++) {
                    samlAttribute.addValue(valueNodes.item(j).getTextContent().trim());
                }

                assertion.addAttribute(samlAttribute);
                logger.debug("Extracted SAML attribute: {} = {}", samlAttribute.getName(), samlAttribute.getValues());
            }
        }

        logger.info("Successfully extracted SAML assertion for user: {}", assertion.getNameId());
        return assertion;
    }

    public static class SamlProcessingException extends Exception {
        public SamlProcessingException(String message) {
            super(message);
        }
        public SamlProcessingException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}

// --- SAML Validation Service ---

package com.enterprise.saml.service;

import com.enterprise.saml.config.SamlServiceProviderConfig;
import com.enterprise.saml.model.SamlAssertion;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.time.Duration;
import java.time.Instant;

@Service
public class SamlValidationService {

    private static final Logger logger = LoggerFactory.getLogger(SamlValidationService.class);
    private static final Duration CLOCK_SKEW = Duration.ofMinutes(5);
    private static final String SUCCESS_STATUS = "urn:oasis:names:tc:SAML:2.0:status:Success";

    @Autowired
    private SamlServiceProviderConfig config;

    public void validateAssertion(SamlAssertion assertion) throws SamlXmlParserService.SamlProcessingException {
        validateStatusCode(assertion);
        validateIssuer(assertion);
        validateAudience(assertion);
        validateTimeConditions(assertion);
        validateNameId(assertion);

        logger.info("SAML assertion validation passed for user: {}", assertion.getNameId());
    }

    private void validateStatusCode(SamlAssertion assertion) throws SamlXmlParserService.SamlProcessingException {
        if (assertion.getStatusCode() == null || !assertion.getStatusCode().equals(SUCCESS_STATUS)) {
            throw new SamlXmlParserService.SamlProcessingException(
                    "SAML response status is not Success: " + assertion.getStatusCode());
        }
    }

    private void validateIssuer(SamlAssertion assertion) throws SamlXmlParserService.SamlProcessingException {
        if (assertion.getIssuer() == null || assertion.getIssuer().isEmpty()) {
            throw new SamlXmlParserService.SamlProcessingException("SAML assertion has no Issuer");
        }
        if (!assertion.getIssuer().equals(config.getIdpEntityId())) {
            throw new SamlXmlParserService.SamlProcessingException(
                    "SAML assertion Issuer mismatch. Expected: " + config.getIdpEntityId() +
                            ", Got: " + assertion.getIssuer());
        }
    }

    private void validateAudience(SamlAssertion assertion) throws SamlXmlParserService.SamlProcessingException {
        if (assertion.getAudience() != null && !assertion.getAudience().isEmpty()) {
            if (!assertion.getAudience().equals(config.getSpEntityId())) {
                throw new SamlXmlParserService.SamlProcessingException(
                        "SAML assertion Audience mismatch. Expected: " + config.getSpEntityId() +
                                ", Got: " + assertion.getAudience());
            }
        }
    }

    private void validateTimeConditions(SamlAssertion assertion) throws SamlXmlParserService.SamlProcessingException {
        Instant now = Instant.now();

        if (assertion.getNotBefore() != null) {
            Instant adjustedNotBefore = assertion.getNotBefore().minus(CLOCK_SKEW);
            if (now.isBefore(adjustedNotBefore)) {
                throw new SamlXmlParserService.SamlProcessingException(
                        "SAML assertion is not yet valid. NotBefore: " + assertion.getNotBefore());
            }
        }

        if (assertion.getNotOnOrAfter() != null) {
            Instant adjustedNotOnOrAfter = assertion.getNotOnOrAfter().plus(CLOCK_SKEW);
            if (now.isAfter(adjustedNotOnOrAfter)) {
                throw new SamlXmlParserService.SamlProcessingException(
                        "SAML assertion has expired. NotOnOrAfter: " + assertion.getNotOnOrAfter());
            }
        }
    }

    private void validateNameId(SamlAssertion assertion) throws SamlXmlParserService.SamlProcessingException {
        if (assertion.getNameId() == null || assertion.getNameId().isEmpty()) {
            throw new SamlXmlParserService.SamlProcessingException("SAML assertion has no NameID");
        }
    }
}

// --- SAML Authentication Service ---

package com.enterprise.saml.service;

import com.enterprise.saml.model.SamlAssertion;
import com.enterprise.saml.model.SamlUserAttributes;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Service;

import jakarta.servlet.http.HttpSession;
import java.util.ArrayList;
import java.util.List;

@Service
public class SamlAuthenticationService {

    private static final Logger logger = LoggerFactory.getLogger(SamlAuthenticationService.class);

    public static final String SAML_USER_ATTRIBUTES_KEY = "SAML_USER_ATTRIBUTES";
    public static final String SAML_ASSERTION_KEY = "SAML_ASSERTION";
    public static final String SAML_AUTHENTICATED_KEY = "SAML_AUTHENTICATED";

    @Autowired
    private SamlXmlParserService xmlParserService;

    @Autowired
    private SamlValidationService validationService;

    public SamlUserAttributes processSamlResponse(String encodedSamlResponse, HttpSession session) throws SamlXmlParserService.SamlProcessingException {
        try {
            // Decode Base64 SAML response
            String samlXml = xmlParserService.decodeBase64SamlResponse(encodedSamlResponse);
            logger.debug("Decoded SAML response XML");

            // Parse XML
            org.w3c.dom.Document document = xmlParserService.parseXml(samlXml);
            logger.debug("Parsed SAML response XML document");

            // Extract assertion
            SamlAssertion assertion = xmlParserService.extractAssertion(document);
            logger.debug("Extracted SAML assertion: {}", assertion.getId());

            // Validate assertion
            validationService.validateAssertion(assertion);
            logger.info("SAML assertion validated successfully for user: {}", assertion.getNameId());

            // Build user attributes
            SamlUserAttributes userAttributes = buildUserAttributes(assertion);

            // Store in session
            storeInSession(session, userAttributes, assertion);

            // Create Spring Security authentication
            createAuthentication(userAttributes);

            return userAttributes;

        } catch (SamlXmlParserService.SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlXmlParserService.SamlProcessingException("Failed to process SAML response", e);
        }
    }

    private SamlUserAttributes buildUserAttributes(SamlAssertion assertion) {
        SamlUserAttributes userAttributes = new SamlUserAttributes();
        userAttributes.setNameId(assertion.getNameId());
        userAttributes.setSessionIndex(assertion.getSessionIndex());
        userAttributes.setIssuer(assertion.getIssuer());
        userAttributes.setAuthenticationInstant(assertion.getAuthnInstant());
        userAttributes.setSessionNotOnOrAfter(assertion.getNotOnOrAfter());

        // Map SAML attributes to user attributes
        for (SamlAssertion.SamlAttribute attribute : assertion.getAttributes()) {
            String name = attribute.getName();
            // Use the first value for simplicity; multi-valued attributes could be handled differently
            String value = attribute.getValues().isEmpty() ? "" : attribute.getValues().get(0);

            // Map common SAML attribute names to friendly names
            String friendlyName = mapAttributeName(name);
            userAttributes.addAttribute(friendlyName, value);

            // Also store with original name
            if (!friendlyName.equals(name)) {
                userAttributes.addAttribute(name, value);
            }
        }

        logger.info("Built user attributes for: {}", userAttributes.getNameId());
        return userAttributes;
    }

    private String mapAttributeName(String samlAttributeName) {
        switch (samlAttributeName) {
            case "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress":
            case "urn:oid:0.9.2342.19200300.100.1.3":
                return "email";
            case "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname":
            case "urn:oid:2.5.4.42":
                return "firstName";
            case "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname":
            case "urn:oid:2.5.4.4":
                return "lastName";
            case "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name":
            case "urn:oid:2.16.840.1.113730.3.1.241":
                return "displayName";
            case "http://schemas.microsoft.com/ws/2008/06/identity/claims/role":
            case "urn:oid:1.3.6.1.4.1.5923.1.1.1.7":
                return "role";
            case "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/upn":
                return "upn";
            case "urn:oid:0.9.2342.19200300.100.1.1":
                return "uid";
            case "urn:oid:1.3.6.1.4.1.5923.1.1.1.6":
                return "eduPersonPrincipalName";
            case "urn:oid:2.5.4.3":
                return "cn";
            case "urn:oid:2.5.4.10":
                return "organization";
            case "urn:oid:2.5.4.11":
                return "department";
            default:
                // Extract the last segment of URI-based attribute names
                if (samlAttributeName.contains("/")) {
                    return samlAttributeName.substring(samlAttributeName.lastIndexOf('/') + 1);
                }
                return samlAttributeName;
        }
    }

    private void storeInSession(HttpSession session, SamlUserAttributes userAttributes, SamlAssertion assertion) {
        session.setAttribute(SAML_USER_ATTRIBUTES_KEY, userAttributes);
        session.setAttribute(SAML_ASSERTION_KEY, assertion);
        session.setAttribute(SAML_AUTHENTICATED_KEY, true);

        // Store individual attributes for easy access
        for (var entry : userAttributes.getAttributes().entrySet()) {
            session.setAttribute("saml_attr_" + entry.getKey(), entry.getValue());
        }

        logger.info("Stored SAML user attributes in session for user: {}", userAttributes.getNameId());
    }

    private void createAuthentication(SamlUserAttributes userAttributes) {
        List<GrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        // Add role-based authorities from SAML attributes
        String role = userAttributes.getAttribute("role");
        if (role != null && !role.isEmpty()) {
            authorities.add(new SimpleGrantedAuthority("ROLE_" + role.toUpperCase()));
        }

        UsernamePasswordAuthenticationToken authentication =
                new UsernamePasswordAuthenticationToken(
                        userAttributes.getNameId(),
                        null,
                        authorities
                );
        authentication.setDetails(userAttributes);

        SecurityContextHolder.getContext().setAuthentication(authentication);
        logger.info("Created Spring Security authentication for user: {}", userAttributes.getNameId());
    }
}

// --- SAML Request Generator Service ---

package com.enterprise.saml.service;

import com.enterprise.saml.config.SamlServiceProviderConfig;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.Base64;
import java.util.UUID;

@Service
public class SamlRequestGeneratorService {

    @Autowired
    private SamlServiceProviderConfig config;

    public String generateAuthnRequest() {
        String id = "_" + UUID.randomUUID().toString();
        String issueInstant = Instant.now().toString();

        String authnRequest = "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                "<samlp:AuthnRequest" +
                " xmlns:samlp=\"urn:oasis:names:tc:SAML:2.0:protocol\"" +
                " xmlns:saml=\"urn:oasis:names:tc:SAML:2.0:assertion\"" +
                " ID=\"" + id + "\"" +
                " Version=\"2.0\"" +
                " IssueInstant=\"" + issueInstant + "\"" +
                " Destination=\"" + config.getIdpSsoUrl() + "\"" +
                " AssertionConsumerServiceURL=\"" + config.getSpAcsUrl() + "\"" +
                " ProtocolBinding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\">" +
                "<saml:Issuer>" + config.getSpEntityId() + "</saml:Issuer>" +
                "<samlp:NameIDPolicy" +
                " Format=\"urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress\"" +
                " AllowCreate=\"true\"/>" +
                "</samlp:AuthnRequest>";

        return Base64.getEncoder().encodeToString(authnRequest.getBytes());
    }

    public String getIdpSsoUrl() {
        return config.getIdpSsoUrl();
    }
}

