package com.enterprise.saml.config;

import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.stereotype.Component;

@Component
@ConfigurationProperties(prefix = "saml")
public class SamlServiceProviderConfig {

    private String spEntityId;
    private String spAcsUrl;
    private String spLogoutUrl;
    private String idpEntityId;
    private String idpSsoUrl;
    private String idpSloUrl;
    private String idpCertificate;
    private int maxAuthenticationAge = 7200;

    public String getSpEntityId() { return spEntityId; }
    public void setSpEntityId(String spEntityId) { this.spEntityId = spEntityId; }

    public String getSpAcsUrl() { return spAcsUrl; }
    public void setSpAcsUrl(String spAcsUrl) { this.spAcsUrl = spAcsUrl; }

    public String getSpLogoutUrl() { return spLogoutUrl; }
    public void setSpLogoutUrl(String spLogoutUrl) { this.spLogoutUrl = spLogoutUrl; }

    public String getIdpEntityId() { return idpEntityId; }
    public void setIdpEntityId(String idpEntityId) { this.idpEntityId = idpEntityId; }

    public String getIdpSsoUrl() { return idpSsoUrl; }
    public void setIdpSsoUrl(String idpSsoUrl) { this.idpSsoUrl = idpSsoUrl; }

    public String getIdpSloUrl() { return idpSloUrl; }
    public void setIdpSloUrl(String idpSloUrl) { this.idpSloUrl = idpSloUrl; }

    public String getIdpCertificate() { return idpCertificate; }
    public void setIdpCertificate(String idpCertificate) { this.idpCertificate = idpCertificate; }

    public int getMaxAuthenticationAge() { return maxAuthenticationAge; }
    public void setMaxAuthenticationAge(int maxAuthenticationAge) { this.maxAuthenticationAge = maxAuthenticationAge; }
}

// --- Spring Security Configuration ---

package com.enterprise.saml.config;

import com.enterprise.saml.filter.SamlSessionFilter;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SamlSessionFilter samlSessionFilter() {
        return new SamlSessionFilter();
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf(csrf -> csrf
                        .ignoringRequestMatchers("/saml/acs", "/saml/slo")
                )
                .authorizeHttpRequests(authz -> authz
                        .requestMatchers("/saml/**", "/login", "/error", "/health").permitAll()
                        .requestMatchers("/dashboard/**", "/profile/**", "/api/**").authenticated()
                        .anyRequest().authenticated()
                )
                .addFilterBefore(samlSessionFilter(), UsernamePasswordAuthenticationFilter.class)
                .logout(logout -> logout
                        .logoutUrl("/logout")
                        .logoutSuccessUrl("/login")
                        .invalidateHttpSession(true)
                        .deleteCookies("JSESSIONID")
                );

        return http.build();
    }
}

// --- SAML Session Filter ---

package com.enterprise.saml.filter;

import com.enterprise.saml.model.SamlUserAttributes;
import com.enterprise.saml.service.SamlAuthenticationService;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

public class SamlSessionFilter extends OncePerRequestFilter {

    private static final Logger logger = LoggerFactory.getLogger(SamlSessionFilter.class);

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        HttpSession session = request.getSession(false);

        if (session != null && SecurityContextHolder.getContext().getAuthentication() == null) {
            Boolean isAuthenticated = (Boolean) session.getAttribute(SamlAuthenticationService.SAML_AUTHENTICATED_KEY);
            SamlUserAttributes userAttributes = (SamlUserAttributes) session.getAttribute(SamlAuthenticationService.SAML_USER_ATTRIBUTES_KEY);

            if (Boolean.TRUE.equals(isAuthenticated) && userAttributes != null) {
                // Check if session has expired based on SAML assertion
                if (userAttributes.getSessionNotOnOrAfter() != null &&
                        Instant.now().isAfter(userAttributes.getSessionNotOnOrAfter())) {
                    logger.info("SAML session expired for user: {}", userAttributes.getNameId());
                    session.invalidate();
                    response.sendRedirect("/login?expired=true");
                    return;
                }

                // Restore authentication from session
                List<SimpleGrantedAuthority> authorities = new ArrayList<>();
                authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

                String role = userAttributes.getAttribute("role");
                if (role != null && !role.isEmpty()) {
                    authorities.add(new SimpleGrantedAuthority("ROLE_" + role.toUpperCase()));
                }

                UsernamePasswordAuthenticationToken authentication =
                        new UsernamePasswordAuthenticationToken(
                                userAttributes.getNameId(),
                                null,
                                authorities
                        );
                authentication.setDetails(userAttributes);
                SecurityContextHolder.getContext().setAuthentication(authentication);
            }
        }

        filterChain.doFilter(request, response);
    }

    @Override
    protected boolean shouldNotFilter(HttpServletRequest request) {
        String path = request.getRequestURI();
        return path.startsWith("/saml/") || path.equals("/login") || path.equals("/health");
    }
}

// --- SAML ACS Controller ---

package com.enterprise.saml.controller;

import com.enterprise.saml.model.SamlUserAttributes;
import com.enterprise.saml.service.SamlAuthenticationService;
import com.enterprise.saml.service.SamlRequestGeneratorService;
import com.enterprise.saml.service.SamlXmlParserService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;

@Controller
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    @Autowired
    private SamlAuthenticationService authenticationService;

    @Autowired
    private SamlRequestGeneratorService requestGeneratorService;

    @GetMapping("/login")
    public String login(Model model, @RequestParam(required = false) String error,
                        @RequestParam(required = false) String expired) {
        if (error != null) {
            model.addAttribute("error", "Authentication failed. Please try again.");
        }
        if (expired != null) {
            model.addAttribute("error", "Your session has expired. Please log in again.");
        }
        return "login";
    }

    @GetMapping("/saml/login")
    public void initiateSamlLogin(HttpServletResponse response) throws IOException {
        String encodedRequest = requestGeneratorService.generateAuthnRequest();
        String idpSsoUrl = requestGeneratorService.getIdpSsoUrl();

        String redirectUrl = idpSsoUrl + "?SAMLRequest=" +
                URLEncoder.encode(encodedRequest, StandardCharsets.UTF_8);

        logger.info("Initiating SAML login, redirecting to IdP: {}", idpSsoUrl);
        response.sendRedirect(redirectUrl);
    }

    @PostMapping("/saml/acs")
    public String assertionConsumerService(
            @RequestParam("SAMLResponse") String samlResponse,
            @RequestParam(value = "RelayState", required = false) String relayState,
            HttpServletRequest request,
            Model model) {

        logger.info("Received SAML response at ACS endpoint");

        try {
            HttpSession session = request.getSession(true);
            SamlUserAttributes userAttributes = authenticationService.processSamlResponse(samlResponse, session);

            logger.info("SAML authentication successful for user: {}", userAttributes.getNameId());

            // Redirect to relay state or default dashboard
            if (relayState != null && !relayState.isEmpty()) {
                return "redirect:" + relayState;
            }
            return "redirect:/dashboard";

        } catch (SamlXmlParserService.SamlProcessingException e) {
            logger.error("SAML authentication failed: {}", e.getMessage(), e);
            model.addAttribute("error", "Authentication failed: " + e.getMessage());
            return "redirect:/login?error=true";
        }
    }

    @GetMapping("/saml/logout")
    public String samlLogout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            SamlUserAttributes userAttributes = (SamlUserAttributes) session.getAttribute(
                    SamlAuthenticationService.SAML_USER_ATTRIBUTES_KEY);
            if (userAttributes != null) {
                logger.info("Logging out SAML user: {}", userAttributes.getNameId());
            }
            session.invalidate();
        }
        org.springframework.security.core.context.SecurityContextHolder.clearContext();
        return "redirect:/login";
    }

    @PostMapping("/saml/slo")
    public String singleLogoutService(
            @RequestParam(value = "SAMLRequest", required = false) String samlRequest,
            @RequestParam(value = "SAMLResponse", required = false) String samlResponse,
            HttpServletRequest request) {

        logger.info("Received SLO request/response");

        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }
        org.springframework.security.core.context.SecurityContextHolder.clearContext();

        return "redirect:/login";
    }

    @GetMapping("/saml/metadata")
    @ResponseBody
    public String metadata() {
        return generateSpMetadata();
    }

    private String generateSpMetadata() {
        return "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                "<md:EntityDescriptor xmlns:md=\"urn:oasis:names:tc:SAML:2.0:metadata\"" +
                " entityID=\"${saml.sp-entity-id}\">" +
                "<md:SPSSODescriptor" +
                " AuthnRequestsSigned=\"false\"" +
                " WantAssertionsSigned=\"true\"" +
                " protocolSupportEnumeration=\"urn:oasis:names:tc:SAML:2.0:protocol\">" +
                "<md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>" +
                "<md:AssertionConsumerService" +
                " Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\"" +
                " Location=\"${saml.sp-acs-url}\"" +
                " index=\"0\" isDefault=\"true\"/>" +
                "<md:SingleLogoutService" +
                " Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\"" +
                " Location=\"${saml.sp-logout-url}\"/>" +
                "</md:SPSSODescriptor>" +
                "</md:EntityDescriptor>";
    }
}

// --- Dashboard Controller ---

package com.enterprise.saml.controller;

import com.enterprise.saml.model.SamlUserAttributes;
import com.enterprise.saml.service.SamlAuthenticationService;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class DashboardController {

    @GetMapping("/dashboard")
    public String dashboard(HttpSession session, Model model) {
        SamlUserAttributes userAttributes = (SamlUserAttributes) session.getAttribute(
                SamlAuthenticationService.SAML_USER_ATTRIBUTES_KEY);

        if (userAttributes != null) {
            model.addAttribute("userAttributes", userAttributes);
            model.addAttribute("nameId", userAttributes.getNameId());
            model.addAttribute("email", userAttributes.getAttribute("email"));
            model.addAttribute("firstName", userAttributes.getAttribute("firstName"));
            model.addAttribute("lastName", userAttributes.getAttribute("lastName"));
            model.addAttribute("displayName", userAttributes.getAttribute("displayName"));
            model.addAttribute("attributes", userAttributes.getAttributes());
        }

        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication != null) {
            model.addAttribute("principal", authentication.getName());
            model.addAttribute("authorities", authentication.getAuthorities());
        }

        return "dashboard";
    }

    @GetMapping("/profile")
    public String profile(HttpSession session, Model model) {
        SamlUserAttributes userAttributes = (SamlUserAttributes) session.getAttribute(
                SamlAuthenticationService.SAML_USER_ATTRIBUTES_KEY);

        if (userAttributes != null) {
            model.addAttribute("userAttributes", userAttributes);
        }

        return "profile";
    }
}

// --- REST API Controller ---

package com.enterprise.saml.controller;

import com.enterprise.saml.model.SamlUserAttributes;
import com.enterprise.saml.service.SamlAuthenticationService;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class SamlApiController {

    @GetMapping("/user")
    public ResponseEntity<Map<String, Object>> getCurrentUser(HttpSession session) {
        SamlUserAttributes userAttributes = (SamlUserAttributes) session.getAttribute(
                SamlAuthenticationService.SAML_USER_ATTRIBUTES_KEY);

        if (userAttributes == null) {
            return ResponseEntity.status(401).body(Map.of("error", "Not authenticated"));
        }

        Map<String, Object> user = new HashMap<>();
        user.put("nameId", userAttributes.getNameId());
        user.put("issuer", userAttributes.getIssuer());
        user.put("authenticationInstant", userAttributes.getAuthenticationInstant());
        user.put("attributes", userAttributes.getAttributes());

        return ResponseEntity.ok(user);
    }

    @GetMapping("/session")
    public ResponseEntity<Map<String, Object>> getSessionInfo(HttpSession session) {
        Map<String, Object> info = new HashMap<>();
        info.put("sessionId", session.getId());
        info.put("creationTime", session.getCreationTime());
        info.put("lastAccessedTime", session.getLastAccessedTime());
        info.put("maxInactiveInterval", session.getMaxInactiveInterval());
        info.put("isAuthenticated", session.getAttribute(SamlAuthenticationService.SAML_AUTHENTICATED_KEY));

        return ResponseEntity.ok(info);
    }

    @GetMapping("/health")
    public ResponseEntity<Map<String, String>> health() {
        return ResponseEntity.ok(Map.of("status", "UP", "service", "SAML Service Provider"));
    }
}

